         if  (v >  3 ) {
             continue  :sw  2 ;
        }  else if  (v ==  3 ) {

             // `break` can target labeled loops. break  :sw;
        }

         continue  :sw  1 ;
    },

     1  =>  return ,

     else  =>  unreachable ,
}
```
}
